import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useAuth } from '../../context/AuthContext';

export default function StudentDashboard() {
  const { user } = useAuth();
  const [profile, setProfile] = useState(null);
  const [fees, setFees] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([axios.get('/students/profile'), axios.get('/fees/my')])
      .then(([p, f]) => { setProfile(p.data); setFees(f.data); })
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  if (loading) return <div className="loading-screen" style={{ height: 300 }}><div className="spinner" /></div>;

  const paid = fees.filter(f => f.status === 'paid');
  const pending = fees.filter(f => f.status === 'pending' || f.status === 'overdue');
  const totalPaid = paid.reduce((s, f) => s + parseFloat(f.totalAmount), 0);
  const totalPending = pending.reduce((s, f) => s + parseFloat(f.totalAmount), 0);
  const fmt = (n) => `₹${Number(n).toLocaleString('en-IN')}`;

  return (
    <div>
      {/* Welcome card */}
      <div className="card" style={{ background: 'linear-gradient(135deg, var(--primary-dark), var(--primary-light))', color: 'white', marginBottom: 20 }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: 12 }}>
          <div>
            <div style={{ fontSize: 13, opacity: 0.8, marginBottom: 4 }}>Welcome back,</div>
            <h2 style={{ fontSize: 22, fontWeight: 800, color: 'white' }}>👋 {user?.name}</h2>
            {profile && <div style={{ fontSize: 13, opacity: 0.8, marginTop: 4 }}>{profile.department} • Year {profile.year} • {profile.studentId}</div>}
          </div>
          {profile?.route && (
            <div style={{ background: 'rgba(255,255,255,0.15)', borderRadius: 12, padding: '12px 20px', textAlign: 'center' }}>
              <div style={{ fontSize: 11, opacity: 0.8, marginBottom: 2 }}>Your Bus Route</div>
              <div style={{ fontWeight: 700, fontSize: 18 }}>🚌 {profile.route.routeNumber}</div>
              <div style={{ fontSize: 12, opacity: 0.8 }}>{profile.route.routeName}</div>
              <div style={{ fontSize: 12, marginTop: 4, color: '#fde68a' }}>📍 {profile.boardingPoint}</div>
            </div>
          )}
        </div>
      </div>

      <div className="stats-grid">
        <div className="stat-card green">
          <div className="stat-label">Total Paid</div>
          <div className="stat-value" style={{ fontSize: 22 }}>{fmt(totalPaid)}</div>
          <div className="stat-sub">{paid.length} payments made</div>
        </div>
        <div className="stat-card yellow">
          <div className="stat-label">Pending Amount</div>
          <div className="stat-value" style={{ fontSize: 22 }}>{fmt(totalPending)}</div>
          <div className="stat-sub">{pending.length} fees pending</div>
        </div>
        <div className="stat-card">
          <div className="stat-label">Monthly Fee</div>
          <div className="stat-value" style={{ fontSize: 22 }}>{profile?.route ? fmt(profile.route.monthlyFee) : '—'}</div>
          <div className="stat-sub">Per month</div>
        </div>
        <div className="stat-card blue">
          <div className="stat-label">Total Records</div>
          <div className="stat-value">{fees.length}</div>
          <div className="stat-sub">Fee records</div>
        </div>
      </div>

      {/* Pending fees alert */}
      {pending.length > 0 && (
        <div className="alert alert-error" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <span>⚠️ You have {pending.length} pending fee(s) totaling {fmt(totalPending)}. Please contact the admin to clear dues.</span>
        </div>
      )}

      {/* Recent fees */}
      <div className="card">
        <div className="card-header"><h3 className="card-title">📋 Recent Fee History</h3></div>
        {fees.length === 0 ? (
          <div className="empty-state"><span className="icon">📭</span><p>No fee records yet</p></div>
        ) : (
          <div className="table-wrap">
            <table>
              <thead><tr><th>Month</th><th>Route</th><th>Amount</th><th>Late Fee</th><th>Total</th><th>Due Date</th><th>Paid On</th><th>Status</th></tr></thead>
              <tbody>
                {fees.slice(0, 10).map(f => (
                  <tr key={f.id}>
                    <td><strong>{f.feeMonth}</strong></td>
                    <td style={{ fontSize: 12 }}>{f.route?.routeNumber}</td>
                    <td>{fmt(f.amount)}</td>
                    <td style={{ color: f.lateFee > 0 ? 'var(--danger)' : 'inherit' }}>{f.lateFee > 0 ? fmt(f.lateFee) : '—'}</td>
                    <td><strong>{fmt(f.totalAmount)}</strong></td>
                    <td style={{ fontSize: 12 }}>{f.dueDate}</td>
                    <td style={{ fontSize: 12 }}>{f.paidDate || '—'}</td>
                    <td><span className={`badge badge-${f.status}`}>{f.status}</span></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}
